    reports.append({
        'id': 'comm_email_queue',
        'name': 'Pending Email Queue',
        'description': 'Emails stuck in queue that have not been sent',
        'help_text': '<strong>Pending Email Queue</strong> shows emails stuck in the send queue. Diagnoses issues like Missing Subject, Empty Body, No Recipients, or Past Due scheduled sends.',
        'category': 'communications',
        'icon': 'fa-hourglass-half',
        'sql_template': '''
            SELECT
                eq.Id AS EmailId,
                eq.Subject,
                p.Name2 AS QueuedBy,
                CONVERT(VARCHAR, eq.Queued, 101) AS QueuedDate,
                DATEDIFF(hour, eq.Queued, GETDATE()) AS HoursOld,
                (SELECT COUNT(*) FROM EmailQueueTo WHERE Id = eq.Id) AS Recipients,
                CASE
                    WHEN eq.Subject IS NULL OR eq.Subject = '' THEN 'Missing Subject'
                    WHEN eq.Body IS NULL OR LEN(eq.Body) = 0 THEN 'Empty Body'
                    WHEN (SELECT COUNT(*) FROM EmailQueueTo WHERE Id = eq.Id) = 0 THEN 'No Recipients'
                    WHEN eq.SendWhen IS NOT NULL AND eq.SendWhen > GETDATE() THEN 'Scheduled: ' + CONVERT(VARCHAR, eq.SendWhen, 101)
                    WHEN eq.SendWhen IS NOT NULL AND eq.SendWhen <= GETDATE() THEN 'Past Due'
                    ELSE 'Processing Issue'
                END AS Issue
            FROM EmailQueue eq
            LEFT JOIN People p ON p.PeopleId = eq.QueuedBy
            WHERE eq.Sent IS NULL
            ORDER BY eq.Queued
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': False},
        'is_builtin': True
    })

    reports.append({
        'id': 'comm_campaign_performance',
        'name': 'Campaign Send Performance',
        'description': 'Email send times, body sizes, and image analysis for large sends',
        'help_text': '<strong>Campaign Send Performance</strong> shows send times, body sizes, and image analysis for email campaigns with 10+ recipients. Helps identify emails that take too long or are too large.',
        'category': 'communications',
        'icon': 'fa-tachometer-alt',
        'sql_template': '''
            SELECT
                eq.Subject,
                p.Name2 AS SentBy,
                CONVERT(VARCHAR, eq.Sent, 101) AS SentDate,
                CASE WHEN eq.SendWhen IS NOT NULL THEN 'Scheduled' ELSE 'Immediate' END AS SendType,
                COUNT(eqt.PeopleId) AS Recipients,
                CASE
                    WHEN DATEDIFF(second, COALESCE(eq.SendWhen, eq.Queued), eq.Sent) < 60
                        THEN CAST(DATEDIFF(second, COALESCE(eq.SendWhen, eq.Queued), eq.Sent) AS VARCHAR) + ' sec'
                    WHEN DATEDIFF(second, COALESCE(eq.SendWhen, eq.Queued), eq.Sent) < 3600
                        THEN CAST(DATEDIFF(minute, COALESCE(eq.SendWhen, eq.Queued), eq.Sent) AS VARCHAR) + ' min'
                    ELSE CAST(CAST(DATEDIFF(minute, COALESCE(eq.SendWhen, eq.Queued), eq.Sent) / 60.0 AS DECIMAL(10,1)) AS VARCHAR) + ' hrs'
                END AS SendTime,
                CASE WHEN eq.Body LIKE '%data:image%' THEN 'Yes' ELSE 'No' END AS EmbeddedImgs,
                (LEN(eq.Body) - LEN(REPLACE(eq.Body, '<img', ''))) / 4 AS Images
            FROM EmailQueue eq WITH (NOLOCK)
            JOIN EmailQueueTo eqt ON eq.Id = eqt.Id
            LEFT JOIN People p ON p.PeopleId = eq.QueuedBy
            WHERE eq.Sent IS NOT NULL
                {filters}
            GROUP BY eq.Id, eq.Subject, eq.Queued, eq.SendWhen, eq.Sent, p.Name2, eq.Body
            HAVING COUNT(eqt.PeopleId) >= 10
            ORDER BY eq.Sent DESC
        ''',
        'parameters': [
            {'name': 'date_range', 'label': 'Sent Date', 'type': 'daterange',
             'sql_column': 'eqt.Sent', 'default': 'last_30_days'}
        ],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': False},
        'is_builtin': True
    })

    # ---- ENGAGEMENT (continued - Involvement Activity) ----

    reports.append({
        'id': 'eng_dormant_orgs',
        'name': 'Dormant Involvements',
        'description': 'Active involvements with no meetings or member changes in 90+ days',
        'help_text': '<strong>Dormant Involvements</strong> finds active involvements with no meetings AND no member changes for 90+ days. These may need to be closed or revived. Sorted by member count (biggest dormant groups first).',
        'category': 'engagement',
        'icon': 'fa-bed',
        'sql_template': '''
            SELECT
                o.OrganizationId AS OrgId,
                o.OrganizationName AS Involvement,
                p.Name AS Program,
                d.Name AS Division,
                o.MemberCount AS Members,
                ot.Description AS OrgType,
                CONVERT(VARCHAR, o.CreatedDate, 101) AS Created,
                CONVERT(VARCHAR, (SELECT MAX(m.MeetingDate) FROM Meetings m
                    WHERE m.OrganizationId = o.OrganizationId), 101) AS LastMeeting,
                CONVERT(VARCHAR, (SELECT MAX(om.EnrollmentDate) FROM OrganizationMembers om
                    WHERE om.OrganizationId = o.OrganizationId), 101) AS LastEnrollment,
                DATEDIFF(day,
                    COALESCE(
                        (SELECT MAX(m.MeetingDate) FROM Meetings m WHERE m.OrganizationId = o.OrganizationId),
                        (SELECT MAX(om.EnrollmentDate) FROM OrganizationMembers om WHERE om.OrganizationId = o.OrganizationId),
                        o.CreatedDate
                    ), GETDATE()) AS DaysSinceActivity
            FROM Organizations o
            JOIN Division d ON o.DivisionId = d.Id
            JOIN Program p ON d.ProgId = p.Id
            LEFT JOIN lookup.OrganizationType ot ON o.OrganizationTypeId = ot.Id
            WHERE o.OrganizationStatusId = 30
                AND (
                    (SELECT MAX(m.MeetingDate) FROM Meetings m WHERE m.OrganizationId = o.OrganizationId) IS NULL
                    OR (SELECT MAX(m.MeetingDate) FROM Meetings m WHERE m.OrganizationId = o.OrganizationId) < DATEADD(day, -90, GETDATE())
                )
                AND (
                    (SELECT MAX(om.EnrollmentDate) FROM OrganizationMembers om WHERE om.OrganizationId = o.OrganizationId) IS NULL
                    OR (SELECT MAX(om.EnrollmentDate) FROM OrganizationMembers om WHERE om.OrganizationId = o.OrganizationId) < DATEADD(day, -90, GETDATE())
                )
                AND (o.CreatedDate IS NULL OR o.CreatedDate < DATEADD(day, -90, GETDATE()))
            ORDER BY o.MemberCount DESC
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': False},
        'is_builtin': True
    })

    reports.append({
        'id': 'eng_org_activity_scores',
        'name': 'Involvement Activity Scores',
        'description': 'All active involvements ranked by activity level (meetings + member changes)',
        'help_text': '<strong>Involvement Activity Scores</strong> ranks every active involvement by activity level (High/Moderate/Low/Dormant) based on recent meetings, new members, and recent drops.',
        'category': 'engagement',
        'icon': 'fa-tachometer-alt',
        'sql_template': '''
            SELECT
                o.OrganizationName AS Involvement,
                p.Name AS Program,
                d.Name AS Division,
                o.MemberCount AS Members,
                ot.Description AS OrgType,
                (SELECT COUNT(*) FROM Meetings m
                    WHERE m.OrganizationId = o.OrganizationId
                    AND m.MeetingDate >= DATEADD(day, -30, GETDATE())) AS RecentMeetings,
                (SELECT COUNT(*) FROM OrganizationMembers om
                    WHERE om.OrganizationId = o.OrganizationId
                    AND om.EnrollmentDate >= DATEADD(day, -45, GETDATE())) AS NewMembers,
                (SELECT COUNT(*) FROM OrganizationMembers om
                    WHERE om.OrganizationId = o.OrganizationId
                    AND om.InactiveDate >= DATEADD(day, -45, GETDATE())
                    AND om.InactiveDate <= GETDATE()) AS RecentDrops,
                CONVERT(VARCHAR, (SELECT MAX(m.MeetingDate) FROM Meetings m
                    WHERE m.OrganizationId = o.OrganizationId), 101) AS LastMeeting,
                CASE
                    WHEN (SELECT COUNT(*) FROM Meetings m WHERE m.OrganizationId = o.OrganizationId
                          AND m.MeetingDate >= DATEADD(day, -30, GETDATE())) >= 3 THEN 'High'
                    WHEN (SELECT COUNT(*) FROM Meetings m WHERE m.OrganizationId = o.OrganizationId
                          AND m.MeetingDate >= DATEADD(day, -30, GETDATE())) >= 1 THEN 'Moderate'
                    WHEN (SELECT COUNT(*) FROM OrganizationMembers om WHERE om.OrganizationId = o.OrganizationId
                          AND om.EnrollmentDate >= DATEADD(day, -45, GETDATE())) > 0 THEN 'Low'
                    ELSE 'Dormant'
                END AS ActivityLevel
            FROM Organizations o
            JOIN Division d ON o.DivisionId = d.Id
            JOIN Program p ON d.ProgId = p.Id
            LEFT JOIN lookup.OrganizationType ot ON o.OrganizationTypeId = ot.Id
            WHERE o.OrganizationStatusId = 30
            ORDER BY
                CASE
                    WHEN (SELECT COUNT(*) FROM Meetings m WHERE m.OrganizationId = o.OrganizationId
                          AND m.MeetingDate >= DATEADD(day, -30, GETDATE())) >= 3 THEN 1
                    WHEN (SELECT COUNT(*) FROM Meetings m WHERE m.OrganizationId = o.OrganizationId
                          AND m.MeetingDate >= DATEADD(day, -30, GETDATE())) >= 1 THEN 2
                    WHEN (SELECT COUNT(*) FROM OrganizationMembers om WHERE om.OrganizationId = o.OrganizationId
                          AND om.EnrollmentDate >= DATEADD(day, -45, GETDATE())) > 0 THEN 3
                    ELSE 4
                END,
                o.MemberCount DESC
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': False},
        'is_builtin': True
    })

    reports.append({
        'id': 'eng_recent_member_changes',
        'name': 'Recent Member Changes',
        'description': 'People recently enrolled or dropped from involvements (last 45 days)',
        'help_text': '<strong>Recent Member Changes</strong> shows all people enrolled or dropped from involvements in the last 45 days. Useful for a quick overview of membership movement across your church.',
        'category': 'engagement',
        'icon': 'fa-user-edit',
        'sql_template': '''
            SELECT
                per.PeopleId,
                CASE
                    WHEN om.InactiveDate IS NOT NULL AND om.InactiveDate <= GETDATE() THEN 'Dropped'
                    ELSE 'Enrolled'
                END AS ChangeType,
                CASE
                    WHEN om.InactiveDate IS NOT NULL AND om.InactiveDate <= GETDATE()
                        THEN CONVERT(VARCHAR, om.InactiveDate, 101)
                    ELSE CONVERT(VARCHAR, om.EnrollmentDate, 101)
                END AS ChangeDate,
                per.Name2 AS PersonName,
                o.OrganizationName AS Involvement,
                p.Name AS Program,
                mt.Description AS MemberType
            FROM OrganizationMembers om
            JOIN Organizations o ON om.OrganizationId = o.OrganizationId
            JOIN People per ON om.PeopleId = per.PeopleId
            JOIN Division d ON o.DivisionId = d.Id
            JOIN Program p ON d.ProgId = p.Id
            LEFT JOIN lookup.MemberType mt ON om.MemberTypeId = mt.Id
            WHERE (om.EnrollmentDate >= DATEADD(day, -45, GETDATE())
                OR (om.InactiveDate IS NOT NULL AND om.InactiveDate <= GETDATE()
                    AND om.InactiveDate >= DATEADD(day, -45, GETDATE())))
                AND o.OrganizationStatusId = 30
                            {filters}
            ORDER BY
                CASE
                    WHEN om.InactiveDate IS NOT NULL AND om.InactiveDate <= GETDATE() THEN om.InactiveDate
                    ELSE om.EnrollmentDate
                END DESC
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': True},
        'is_builtin': True
    })

    reports.append({
        'id': 'eng_program_summary',
        'name': 'Program Health Summary',
        'description': 'Programs and divisions with involvement counts, member totals, and activity levels',
        'help_text': '<strong>Program Health Summary</strong> provides a bird\'s-eye view of each program and division: how many involvements, total members, how many are active (met in last 30 days), and how many are dormant (no meeting in 90+ days).',
        'category': 'engagement',
        'icon': 'fa-sitemap',
        'sql_template': '''
            WITH OrgActivity AS (
                SELECT
                    o.OrganizationId,
                    o.DivisionId,
                    o.MemberCount,
                    CASE WHEN EXISTS (SELECT 1 FROM Meetings m
                        WHERE m.OrganizationId = o.OrganizationId
                        AND m.MeetingDate >= DATEADD(day, -30, GETDATE())) THEN 1 ELSE 0 END AS IsActive,
                    CASE WHEN NOT EXISTS (SELECT 1 FROM Meetings m
                        WHERE m.OrganizationId = o.OrganizationId
                        AND m.MeetingDate >= DATEADD(day, -90, GETDATE())) THEN 1 ELSE 0 END AS IsDormant
                FROM Organizations o
                WHERE o.OrganizationStatusId = 30
            )
            SELECT
                p.Name AS Program,
                d.Name AS Division,
                COUNT(DISTINCT oa.OrganizationId) AS Involvements,
                SUM(ISNULL(oa.MemberCount, 0)) AS TotalMembers,
                SUM(oa.IsActive) AS ActiveOrgs,
                SUM(oa.IsDormant) AS DormantOrgs
            FROM OrgActivity oa
            JOIN Division d ON oa.DivisionId = d.Id
            JOIN Program p ON d.ProgId = p.Id
            GROUP BY p.Name, d.Name
            ORDER BY p.Name, d.Name
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': False},
        'is_builtin': True
    })

    # ---- ENGAGEMENT (continued - Group Growth/Decline) ----

    reports.append({
        'id': 'eng_group_lifecycle',
        'name': 'Group Lifecycle Stages',
        'description': 'All active groups classified as New, Growing, Stable, Declining, or Dormant',
        'help_text': '<strong>Group Lifecycle Stages</strong> classifies every active group as New (&lt;6 months), Growing (&gt;5% growth), Stable, Declining (&gt;5% decline), or Dormant (no recent meetings). Based on 8-week attendance comparison.',
        'category': 'engagement',
        'icon': 'fa-seedling',
        'sql_template': '''
            WITH GroupData AS (
                SELECT
                    o.OrganizationId,
                    o.OrganizationName AS GroupName,
                    p.Name AS Program,
                    d.Name AS Division,
                    o.MemberCount AS Members,
                    DATEDIFF(month, COALESCE(o.CreatedDate, DATEADD(year,-5,GETDATE())), GETDATE()) AS AgeMonths,
                    COUNT(DISTINCT CASE WHEN a.MeetingDate >= DATEADD(week,-16,GETDATE())
                        AND a.MeetingDate < DATEADD(week,-8,GETDATE()) THEN a.PeopleId END) AS PrevPeriod,
                    COUNT(DISTINCT CASE WHEN a.MeetingDate >= DATEADD(week,-8,GETDATE())
                        THEN a.PeopleId END) AS RecentPeriod,
                    COUNT(DISTINCT CASE WHEN m.MeetingDate >= DATEADD(week,-4,GETDATE())
                        THEN m.MeetingId END) AS RecentMeetings,
                    MAX(m.MeetingDate) AS LastMeeting
                FROM Organizations o
                JOIN Division d ON o.DivisionId = d.Id
                JOIN Program p ON d.ProgId = p.Id
                LEFT JOIN Meetings m ON o.OrganizationId = m.OrganizationId
                LEFT JOIN Attend a ON m.MeetingId = a.MeetingId AND a.AttendanceFlag = 1
                WHERE o.OrganizationStatusId = 30
                GROUP BY o.OrganizationId, o.OrganizationName, p.Name, d.Name,
                    o.MemberCount, o.CreatedDate
            )
            SELECT
                GroupName, Program, Division, Members,
                PrevPeriod, RecentPeriod,
                CASE
                    WHEN PrevPeriod = 0 AND RecentPeriod > 0 THEN 100
                    WHEN PrevPeriod > 0 THEN CAST((RecentPeriod - PrevPeriod) * 100.0 / PrevPeriod AS DECIMAL(5,1))
                    ELSE 0
                END AS GrowthPct,
                CASE
                    WHEN AgeMonths <= 6 THEN 'New'
                    WHEN RecentMeetings = 0 THEN 'Dormant'
                    WHEN PrevPeriod > 0 AND (RecentPeriod - PrevPeriod) * 100.0 / PrevPeriod > 5 THEN 'Growing'
                    WHEN PrevPeriod > 0 AND (RecentPeriod - PrevPeriod) * 100.0 / PrevPeriod < -5 THEN 'Declining'
                    ELSE 'Stable'
                END AS LifecycleStage,
                CONVERT(VARCHAR, LastMeeting, 101) AS LastMeeting,
                RecentMeetings
            FROM GroupData
            ORDER BY
                CASE
                    WHEN AgeMonths <= 6 THEN 1
                    WHEN RecentMeetings = 0 THEN 5
                    WHEN PrevPeriod > 0 AND (RecentPeriod - PrevPeriod) * 100.0 / PrevPeriod > 5 THEN 2
                    WHEN PrevPeriod > 0 AND (RecentPeriod - PrevPeriod) * 100.0 / PrevPeriod < -5 THEN 4
                    ELSE 3
                END,
                Program, Division, GroupName
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table',
                    'formats': {'GrowthPct': 'percent'}},
        'bluetoolbar': {'supported': False},
        'is_builtin': True
    })

