# ============================================================================
# REPORT EXECUTION ENGINE
# ============================================================================

def execute_report(report_def, filter_values, bt_people_ids=None, settings=None):
    """Execute a report SQL with filters applied. Returns dict with rows, columns, error."""
    sql = report_def.get('sql_template', '')
    if not sql:
        return {'error': 'No SQL template defined', 'rows': [], 'columns': []}

    params = report_def.get('parameters', [])
    where_clauses = build_where_clauses(params, filter_values, bt_people_ids, settings)

    # Build filter string
    filter_sql = ''
    if where_clauses:
        filter_sql = 'AND ' + ' AND '.join(where_clauses)

    # Replace placeholders
    sql = sql.replace('{filters}', filter_sql)
    sql = sql.replace('{filters_where}', ('WHERE ' + ' AND '.join(where_clauses)) if where_clauses else '')
    sql = sql.replace('{bluetoolbar_filter}', '')

    rows = []
    columns = []

    # Try to extract column order from SQL SELECT clause (preserves intended order)
    sql_columns = []
    try:
        # For CTE queries (WITH ... AS ...), find the outermost SELECT after all CTEs
        # For regular queries, find the first SELECT
        parse_sql = sql.strip()
        if re.match(r'\s*WITH\s', parse_sql, re.IGNORECASE):
            # Find the last SELECT that's not inside a CTE — look for SELECT after the last )
            # Strategy: find all SELECT positions, use the last one that's followed by FROM
            all_selects = [m.start() for m in re.finditer(r'\bSELECT\b', parse_sql, re.IGNORECASE)]
            select_match = None
            for pos in reversed(all_selects):
                chunk = parse_sql[pos:]
                m = re.match(r'SELECT\s+(TOP\s+\d+\s+)?(.*?)\s+FROM\s', chunk, re.IGNORECASE | re.DOTALL)
                if m:
                    select_match = m
                    break
        else:
            select_match = re.search(r'SELECT\s+(TOP\s+\d+\s+)?(.*?)\s+FROM\s', parse_sql, re.IGNORECASE | re.DOTALL)
        if select_match:
            select_part = select_match.group(2)
            # Split by comma, extract the AS alias or last word
            for chunk in select_part.split(','):
                chunk = chunk.strip()
                if not chunk:
                    continue
                # Look for AS alias (with or without brackets)
                as_match = re.search(r'\bAS\s+\[?(\w+)\]?\s*$', chunk, re.IGNORECASE)
                if as_match:
                    sql_columns.append(as_match.group(1))
                else:
                    # Last word after any dots (e.g., p.Name2 -> Name2)
                    word_match = re.search(r'(\w+)\s*$', chunk)
                    if word_match:
                        sql_columns.append(word_match.group(1))
    except:
        pass

    try:
        results = q.QuerySql(sql)
        first = True
        for r in results:
            if first:
                # Get available attributes from the result object
                available = set()
                for attr in dir(r):
                    if not attr.startswith('_') and attr not in ('Count', 'Keys', 'Values', 'Items',
                        'GetType', 'ToString', 'Equals', 'GetHashCode', 'ReferenceEquals'):
                        try:
                            getattr(r, attr)
                            available.add(attr)
                        except:
                            pass
                # Use SQL order if we parsed it, matching against available attrs (case-insensitive)
                if sql_columns:
                    avail_lower = {a.lower(): a for a in available}
                    for sc in sql_columns:
                        actual = avail_lower.get(sc.lower())
                        if actual and actual not in columns:
                            columns.append(actual)
                    # Add any remaining attrs not in our parsed list
                    for a in sorted(available):
                        if a not in columns:
                            columns.append(a)
                else:
                    columns = sorted(list(available))
                first = False
            row = {}
            for col in columns:
                try:
                    val = getattr(r, col)
                    if val is None:
                        row[col] = ''
                    else:
                        row[col] = safe_str(val)
                except:
                    row[col] = ''
            rows.append(row)
    except Exception as e:
        return {'error': safe_str(e), 'rows': [], 'columns': []}

    return {'rows': rows, 'columns': columns, 'error': None, 'row_count': len(rows)}

