def render_table_html(result, report_def):
    """Render AG Grid container div. Actual grid is built client-side from JSON data."""
    rows = result.get('rows', [])
    columns = result.get('columns', [])

    if not rows:
        return '<div class="rb-empty"><i class="fas fa-inbox"></i><p>No data found for the selected filters.</p></div>'

    return '<div id="rb-grid" class="ag-theme-alpine" style="width:100%;height:500px;"></div>'

def render_grid_data(result, report_def):
    """Return AG Grid columnDefs and rowData as JSON for client-side rendering."""
    rows = result.get('rows', [])
    columns = result.get('columns', [])
    display = report_def.get('display', {})
    formats = display.get('formats', {})

    # Dynamic year labels for 5-year giving and similar
    year_labels = {}
    if display.get('dynamic_labels'):
        try:
            cy = datetime.datetime.now().year
            year_labels = {
                'Y_MINUS_4': str(cy - 4),
                'Y_MINUS_3': str(cy - 3),
                'Y_MINUS_2': str(cy - 2),
                'Y_MINUS_1': str(cy - 1),
                'Y_CURRENT': str(cy),
            }
        except:
            pass

    col_defs = []
    for col in columns:
        label = year_labels.get(col, re.sub(r'([a-z])([A-Z])', r'\1 \2', col))
        fmt = formats.get(col, '')
        cdef = {
            'field': col,
            'headerName': label,
            'sortable': True,
            'filter': True,
            'resizable': True
        }
        # Auto-detect numeric columns for right-align and formatting
        if fmt == 'currency':
            cdef['type'] = 'numericColumn'
            cdef['valueFormatter'] = '__currency__'
        elif fmt == 'percent':
            cdef['type'] = 'numericColumn'
            cdef['valueFormatter'] = '__percent__'
        elif fmt == 'number':
            cdef['type'] = 'numericColumn'
            cdef['valueFormatter'] = '__number__'
        else:
            # Sniff first row to detect numeric
            if rows:
                sample = rows[0].get(col, '')
                try:
                    float(sample)
                    if sample != '':
                        cdef['type'] = 'numericColumn'
                except:
                    pass
        col_defs.append(cdef)

    # Format row values - convert numeric strings to actual numbers for sorting
    formatted_rows = []
    for row in rows:
        frow = {}
        for col in columns:
            val = row.get(col, '')
            # Try to convert to number for proper sorting
            try:
                fval = float(val)
                frow[col] = int(fval) if fval == int(fval) else fval
            except:
                frow[col] = val
        formatted_rows.append(frow)

    return sanitize_for_json({
        'columnDefs': col_defs,
        'rowData': formatted_rows
    })

def render_kpi_html(result, report_def):
    """Render report results as KPI cards.

    Three modes:
    1. Few rows (<=8) with 2+ columns: label/value pairs (category summaries)
    2. Many rows, already-aggregated (no PeopleId, few columns): first-row values
    3. Many rows, person-level data (has PeopleId or many rows): auto-aggregate
       with smart summaries — total count, averages, sums, top categories
    """
    rows = result.get('rows', [])
    columns = result.get('columns', [])
    formats = report_def.get('display', {}).get('formats', {})

    if not rows:
        return '<div class="rb-empty"><i class="fas fa-inbox"></i><p>No data found.</p></div>'

    colors = ['#2563eb', '#059669', '#7c3aed', '#dc2626', '#d97706', '#0891b2', '#4f46e5', '#be185d']

    def _kpi_card(value, label, color, subtitle=''):
        h = '<div class="rb-kpi-card" style="border-top:4px solid {0};">'.format(color)
        h += '<div class="rb-kpi-value">{0}</div>'.format(html_escape(str(value)))
        h += '<div class="rb-kpi-label">{0}</div>'.format(html_escape(str(label)))
        if subtitle:
            h += '<div style="font-size:11px;color:#94a3b8;margin-top:4px">{0}</div>'.format(html_escape(str(subtitle)))
        h += '</div>'
        return h

    def _friendly_label(col):
        return re.sub(r'([a-z])([A-Z])', r'\1 \2', col).replace('_', ' ')

    # Columns to skip for KPI aggregation (IDs, contact info, names, dates as text)
    skip_cols = set()
    for c in columns:
        cl = c.lower()
        # Skip IDs
        if cl in ('peopleid', 'people_id', 'peopleid2', 'familyid', 'family_id',
                   'organizationid', 'org_id', 'orgid', 'userid', 'user_id',
                   'parentpeopleid', 'spousepeopleid', 'leaderid', 'spouseid'):
            skip_cols.add(c)
        # Skip contact info (phone, email, address) — not meaningful as aggregates
        elif any(x in cl for x in ('phone', 'email', 'address', 'city', 'state', 'zip',
                                    'username', 'url', 'link')):
            skip_cols.add(c)
        # Skip name columns (aggregating names is meaningless)
        elif cl in ('name', 'name2', 'fullname', 'full_name', 'personname', 'person_name',
                     'parentname', 'parent_name', 'spousename', 'spouse_name', 'spouse',
                     'headofhouse', 'leadername', 'leader_name', 'childname',
                     'children', 'emergencycontact', 'doctor', 'insurance', 'policy',
                     'involvement', 'organizationname', 'org_name', 'program', 'division'):
            skip_cols.add(c)
        # Skip date-formatted strings (mm/dd/yyyy pattern columns)
        elif any(x in cl for x in ('date', 'created', 'enrolled', 'dropped', 'lastactive',
                                    'lastattend', 'lastattended', 'firstvisit', 'lastlogin')):
            skip_cols.add(c)

    html = ['<div class="rb-kpi-grid">']

    # --- MODE 1: Few rows with label/value pattern (category summaries) ---
    if len(rows) <= 8 and len(columns) >= 2:
        label_col = columns[0]
        value_col = columns[1]
        for i, row in enumerate(rows):
            color = colors[i % len(colors)]
            label = row.get(label_col, '')
            val = row.get(value_col, '')
            fmt = formats.get(value_col, '')
            if fmt == 'currency':
                val = fmt_currency(val)
            elif fmt == 'percent':
                val = fmt_pct(val)
            else:
                val = fmt_number(val)
            html.append(_kpi_card(val, label, color))

    # --- MODE 2+3: Many rows — auto-aggregate ---
    else:
        ci = 0
        # Always start with total record count
        html.append(_kpi_card(fmt_number(len(rows)), 'Total Records', colors[ci % len(colors)]))
        ci += 1

        # Analyze each column for smart aggregation
        for col in columns:
            if col in skip_cols:
                continue
            fmt = formats.get(col, '')
            label = _friendly_label(col)

            # Collect non-empty values
            vals = []
            num_vals = []
            for row in rows:
                v = row.get(col, '')
                if v is None or str(v).strip() == '':
                    continue
                vals.append(str(v))
                try:
                    num_vals.append(float(v))
                except:
                    pass

            if not vals:
                continue

            # Decide: numeric column vs categorical column
            numeric_ratio = float(len(num_vals)) / len(vals) if vals else 0

            if numeric_ratio >= 0.8 and num_vals:
                # Numeric column — show appropriate aggregate
                avg_val = sum(num_vals) / len(num_vals)
                total_val = sum(num_vals)
                min_val = min(num_vals)
                max_val = max(num_vals)

                if fmt == 'currency':
                    # Currency: show total
                    html.append(_kpi_card(fmt_currency(total_val), 'Total ' + label, colors[ci % len(colors)],
                                          'Avg: ' + fmt_currency(avg_val)))
                    ci += 1
                elif fmt == 'percent':
                    # Percent: show average
                    html.append(_kpi_card(fmt_pct(avg_val), 'Avg ' + label, colors[ci % len(colors)],
                                          'Range: ' + fmt_pct(min_val) + ' - ' + fmt_pct(max_val)))
                    ci += 1
                elif col.lower() in ('age',):
                    # Age: show average + range
                    html.append(_kpi_card(fmt_number(round(avg_val, 1)), 'Avg ' + label, colors[ci % len(colors)],
                                          'Range: ' + fmt_number(int(min_val)) + ' - ' + fmt_number(int(max_val))))
                    ci += 1
                elif 'count' in col.lower() or 'total' in col.lower() or 'visits' in col.lower():
                    # Count/Total columns: show sum + average
                    # Avoid "Total Total Visits" — don't add prefix if label already starts with Total/Count
                    sum_label = label if label.lower().startswith(('total', 'count')) else 'Total ' + label
                    html.append(_kpi_card(fmt_number(int(total_val)), sum_label, colors[ci % len(colors)],
                                          'Avg: ' + fmt_number(round(avg_val, 1))))
                    ci += 1
                elif 'days' in col.lower() or 'gap' in col.lower():
                    # Days/gap columns: show average
                    html.append(_kpi_card(fmt_number(round(avg_val, 1)), 'Avg ' + label, colors[ci % len(colors)],
                                          'Range: ' + fmt_number(int(min_val)) + ' - ' + fmt_number(int(max_val))))
                    ci += 1
                elif 'pct' in col.lower() or 'rate' in col.lower() or 'percent' in col.lower():
                    # Percentage fields without explicit format
                    html.append(_kpi_card(fmt_pct(avg_val), 'Avg ' + label, colors[ci % len(colors)],
                                          'Range: ' + fmt_pct(min_val) + ' - ' + fmt_pct(max_val)))
                    ci += 1
                else:
                    # Generic numeric: show average
                    html.append(_kpi_card(fmt_number(round(avg_val, 1)), 'Avg ' + label, colors[ci % len(colors)],
                                          'Sum: ' + fmt_number(int(total_val))))
                    ci += 1
            else:
                # Categorical column — show top value + unique count
                value_counts = {}
                for v in vals:
                    value_counts[v] = value_counts.get(v, 0) + 1
                unique_count = len(value_counts)
                # Skip if too many unique values (like names/emails) — not useful as KPI
                if unique_count > len(rows) * 0.7:
                    continue
                # Find most common value
                sorted_vc = sorted(value_counts.items(), key=lambda x: -x[1])
                top_val = sorted_vc[0][0]
                top_count = sorted_vc[0][1]
                top_pct = round(float(top_count) / len(rows) * 100, 1)
                html.append(_kpi_card(str(top_val), 'Top ' + label, colors[ci % len(colors)],
                                      str(top_count) + ' (' + str(top_pct) + '%) of ' + str(len(rows)) +
                                      (' | ' + str(unique_count) + ' unique' if unique_count > 1 else '')))
                ci += 1

            # Limit to 8 KPI cards max
            if ci >= 8:
                break

    html.append('</div>')
    return ''.join(html)

def render_chart_data_json(result, report_def):
    """Return JSON config for Chart.js rendering on client side."""
    rows = result.get('rows', [])
    display = report_def.get('display', {})
    chart_type = display.get('chart_type', 'bar')
    label_col = display.get('chart_label_col', '')
    data_cols = display.get('chart_data_cols', [])

    if not rows or not label_col:
        return json.dumps({'type': chart_type, 'labels': [], 'datasets': []})

    # Dynamic year labels for chart legend
    year_labels = {}
    if display.get('dynamic_labels'):
        try:
            cy = datetime.datetime.now().year
            year_labels = {
                'Y_MINUS_4': str(cy - 4), 'Y_MINUS_3': str(cy - 3),
                'Y_MINUS_2': str(cy - 2), 'Y_MINUS_1': str(cy - 1),
                'Y_CURRENT': str(cy),
            }
        except:
            pass

    labels = [safe_str(r.get(label_col, '')) for r in rows]

    chart_colors = [
        'rgba(37, 99, 235, 0.7)', 'rgba(5, 150, 105, 0.7)', 'rgba(124, 58, 237, 0.7)',
        'rgba(220, 38, 38, 0.7)', 'rgba(217, 119, 6, 0.7)', 'rgba(8, 145, 178, 0.7)',
        'rgba(79, 70, 229, 0.7)', 'rgba(190, 24, 93, 0.7)'
    ]
    border_colors = [c.replace('0.7', '1') for c in chart_colors]

    datasets = []
    for di, dc in enumerate(data_cols):
        data = []
        for r in rows:
            try:
                data.append(float(r.get(dc, 0)))
            except:
                data.append(0)
        ds_label = year_labels.get(dc, re.sub(r'([a-z])([A-Z])', r'\1 \2', dc))
        if chart_type == 'pie':
            datasets.append({
                'label': ds_label, 'data': data,
                'backgroundColor': chart_colors[:len(data)],
                'borderColor': border_colors[:len(data)], 'borderWidth': 1
            })
        else:
            datasets.append({
                'label': ds_label, 'data': data,
                'backgroundColor': chart_colors[di % len(chart_colors)],
                'borderColor': border_colors[di % len(border_colors)],
                'borderWidth': 2, 'fill': False
            })

    return json.dumps(sanitize_for_json({
        'type': chart_type, 'labels': labels, 'datasets': datasets
    }))

def render_csv(result):
    """Render results as CSV string."""
    rows = result.get('rows', [])
    columns = result.get('columns', [])
    lines = []
    lines.append(','.join('"' + col.replace('"', '""') + '"' for col in columns))
    for row in rows:
        vals = []
        for col in columns:
            v = row.get(col, '')
            vals.append('"' + safe_str(v).replace('"', '""') + '"')
        lines.append(','.join(vals))
    return '\n'.join(lines)

# ============================================================================
# FILTER PANEL RENDERER
# ============================================================================

def render_filter_panel(report_def):
    """Generate HTML for the dynamic filter panel."""
    params = report_def.get('parameters', [])
    if not params:
        return ''

    html = ['<div class="rb-filter-bar">']

    for p in params:
        pname = p.get('name', '')
        plabel = p.get('label', pname)
        ptype = p.get('type', '')
        pdefault = p.get('default', '')

        html.append('<div class="rb-filter-group">')
        html.append('<label>{0}</label>'.format(html_escape(plabel)))

        if ptype == 'daterange':
            html.append('<select name="filter_{0}" class="rb-filter-input rb-daterange-select" data-param="{0}">'.format(pname))
            presets = [
                ('last_30_days', 'Last 30 Days'), ('last_90_days', 'Last 90 Days'),
                ('last_6_months', 'Last 6 Months'), ('last_12_months', 'Last 12 Months'),
                ('ytd', 'Year to Date'), ('fiscal_ytd', 'Fiscal Year to Date'),
                ('custom', 'Custom Range...')
            ]
            for val, label in presets:
                sel = ' selected' if val == pdefault else ''
                html.append('<option value="{0}"{1}>{2}</option>'.format(val, sel, label))
            html.append('</select>')
            html.append('<div class="rb-custom-date-row" style="display:none;">')
            html.append('<input type="date" class="rb-filter-input rb-date-start" data-param="{0}_start" />'.format(pname))
            html.append('<span> to </span>')
            html.append('<input type="date" class="rb-filter-input rb-date-end" data-param="{0}_end" />'.format(pname))
            html.append('</div>')

        elif ptype == 'dropdown':
            source_sql = p.get('source_sql', '')
            html.append('<select name="filter_{0}" class="rb-filter-input" data-param="{0}">'.format(pname))
            html.append('<option value="">All</option>')
            if source_sql:
                try:
                    for r in q.QuerySql(source_sql):
                        v = safe_str(r.value)
                        l = safe_str(r.label)
                        html.append('<option value="{0}">{1}</option>'.format(html_escape(v), html_escape(l)))
                except:
                    pass
            html.append('</select>')

        elif ptype == 'multi_select':
            source_sql = p.get('source_sql', '')
            html.append('<select name="filter_{0}" class="rb-filter-input rb-multi-select" data-param="{0}" multiple style="min-height:80px;">'.format(pname))
            if source_sql:
                try:
                    for r in q.QuerySql(source_sql):
                        v = safe_str(r.value)
                        l = safe_str(r.label)
                        html.append('<option value="{0}">{1}</option>'.format(html_escape(v), html_escape(l)))
                except:
                    pass
            html.append('</select>')
            html.append('<div style="font-size:10px;color:#94a3b8;margin-top:2px;">Hold Ctrl/Cmd to select multiple</div>')

        elif ptype == 'text':
            html.append('<input type="text" class="rb-filter-input" data-param="{0}" placeholder="Search..." />'.format(pname))

        elif ptype == 'number':
            html.append('<input type="number" class="rb-filter-input" data-param="{0}" placeholder="0" />'.format(pname))

        html.append('</div>')

    html.append('<div class="rb-filter-group rb-filter-actions">')
    html.append('<button class="rb-btn rb-btn-primary" onclick="RB.runReport()"><i class="fas fa-play"></i> Run Report</button>')
    html.append('</div>')
    html.append('</div>')

    return ''.join(html)

# ============================================================================
# CUSTOM REPORT MANAGEMENT
# ============================================================================

def load_custom_reports(user_id):
    """Load custom reports: shared catalog + user-specific."""
    reports = []
    shared = load_content_json(CONTENT_CATALOG, {'reports': []})
    for r in shared.get('reports', []):
        r['is_builtin'] = False
        r['is_shared'] = True
        reports.append(r)
    user_reports = load_content_json(CONTENT_USER_PREFIX + str(user_id), {'reports': []})
    for r in user_reports.get('reports', []):
        r['is_builtin'] = False
        r['is_shared'] = False
        reports.append(r)
    return reports

def save_custom_report(user_id, report_def, shared=False):
    """Save a custom report definition."""
    if shared:
        catalog = load_content_json(CONTENT_CATALOG, {'reports': []})
        existing = [i for i, r in enumerate(catalog['reports']) if r.get('id') == report_def.get('id')]
        if existing:
            catalog['reports'][existing[0]] = report_def
        else:
            catalog['reports'].append(report_def)
        return save_content_json(CONTENT_CATALOG, catalog)
    else:
        key = CONTENT_USER_PREFIX + str(user_id)
        user_data = load_content_json(key, {'reports': []})
        existing = [i for i, r in enumerate(user_data['reports']) if r.get('id') == report_def.get('id')]
        if existing:
            user_data['reports'][existing[0]] = report_def
        else:
            user_data['reports'].append(report_def)
        return save_content_json(key, user_data)

def delete_custom_report(user_id, report_id, shared=False):
    """Delete a custom report."""
    if shared:
        catalog = load_content_json(CONTENT_CATALOG, {'reports': []})
        catalog['reports'] = [r for r in catalog['reports'] if r.get('id') != report_id]
        return save_content_json(CONTENT_CATALOG, catalog)
    else:
        key = CONTENT_USER_PREFIX + str(user_id)
        user_data = load_content_json(key, {'reports': []})
        user_data['reports'] = [r for r in user_data['reports'] if r.get('id') != report_id]
        return save_content_json(key, user_data)

# ============================================================================
# REPORT LOOKUP HELPERS
# ============================================================================

def get_all_reports(user_id, settings=None):
    """Get all reports: built-in + custom, filtered by role access."""
    if settings is None:
        settings = load_settings()
    all_reports = get_default_reports()
    all_reports.extend(load_custom_reports(user_id))
    # Filter by category + report-level role access
    visible = []
    for r in all_reports:
        cat = r.get('category', 'custom')
        rid = r.get('id', '')
        if user_has_report_access(rid, cat, settings):
            visible.append(r)
    return visible

def find_report(report_id, user_id):
    """Find a report by ID from built-in and custom reports."""
    for r in get_all_reports(user_id):
        if r.get('id') == report_id:
            return r
    return None

# ============================================================================
# AJAX HANDLER
# ============================================================================

def handle_ajax(action, user_id, bt_people_ids):
    """Handle AJAX requests. Returns JSON response string."""
    settings = load_settings()

    if action == 'run_report':
        report_id = get_param('report_id')
        display_type = get_param('display_type', 'table')
        report_def = find_report(report_id, user_id)
        if not report_def:
            return json.dumps({'success': False, 'error': 'Report not found: ' + report_id})

        # Role check: verify user can access this report's category
        cat = report_def.get('category', '')
        if not user_has_category_access(cat, settings):
            return json.dumps({'success': False, 'error': 'Access denied: you do not have permission for ' + cat + ' reports'})

        filter_values = {}
        for p in report_def.get('parameters', []):
            pname = p['name']
            ptype = p.get('type', '')
            val = get_param('filter_' + pname, '')
            if ptype == 'daterange' and val == 'custom':
                start = get_param('filter_' + pname + '_start', '')
                end = get_param('filter_' + pname + '_end', '')
                val = (start + '|' + end) if start and end else ''
            filter_values[pname] = val

        use_bt = bt_people_ids if report_def.get('bluetoolbar', {}).get('supported', False) else None
        result = execute_report(report_def, filter_values, use_bt, settings)

        if result.get('error'):
            return json.dumps(sanitize_for_json({'success': False, 'error': result['error']}))

        # Always include grid data for AG Grid rendering
