def build_sidebar_html(all_reports):
    html = []
    html.append('<div class="rb-sidebar">')
    html.append('<div class="rb-sidebar-header">')
    html.append('<h3><i class="fas fa-chart-bar"></i> Reports</h3>')
    html.append('<input type="text" id="rb-search" class="rb-search-input" placeholder="Search reports..." oninput="RB.filterSidebar()" />')
    html.append('</div>')
    html.append('<div class="rb-sidebar-nav">')

    cat_reports = {}
    for r in all_reports:
        cat = r.get('category', 'custom')
        if cat not in cat_reports:
            cat_reports[cat] = []
        cat_reports[cat].append(r)

    cat_order = ['attendance', 'demographics', 'engagement', 'membership', 'financial', 'communications', 'emergency', 'admin']
    rendered = set()

    for ck in cat_order:
        if ck not in cat_reports:
            continue
        rendered.add(ck)
        ci = CATEGORIES.get(ck, {'name': ck.title(), 'icon': 'fa-folder', 'color': '#64748b'})
        html.append('<div class="rb-cat-section">')
        html.append('<div class="rb-cat-header" onclick="RB.toggleCategory(this)">')
        html.append('<span class="rb-cat-icon" style="background:{0}"><i class="fas {1}"></i></span>'.format(ci['color'], ci['icon']))
        html.append('<span>{0}</span>'.format(html_escape(ci['name'])))
        html.append('<span class="rb-cat-arrow"><i class="fas fa-chevron-right"></i></span>')
        html.append('</div><div class="rb-cat-body">')
        for r in cat_reports[ck]:
            html.append('<div class="rb-report-item" data-id="{0}" onclick="RB.selectReport(\'{0}\')">'.format(html_escape(r['id'])))
            html.append('<i class="fas {0}"></i> {1}</div>'.format(r.get('icon', 'fa-file-alt'), html_escape(r.get('name', ''))))
        html.append('</div></div>')

    # Custom reports
    custom_cats = [k for k in cat_reports if k not in rendered]
    if custom_cats:
        html.append('<div class="rb-cat-section">')
        html.append('<div class="rb-cat-header open" onclick="RB.toggleCategory(this)">')
        html.append('<span class="rb-cat-icon" style="background:#8b5cf6"><i class="fas fa-puzzle-piece"></i></span>')
        html.append('<span>Custom Reports</span>')
        html.append('<span class="rb-cat-arrow"><i class="fas fa-chevron-right"></i></span>')
        html.append('</div><div class="rb-cat-body open">')
        for ck in custom_cats:
            for r in cat_reports[ck]:
                html.append('<div class="rb-report-item" data-id="{0}" onclick="RB.selectReport(\'{0}\')">'.format(html_escape(r['id'])))
                html.append('<i class="fas {0}"></i> {1}'.format(r.get('icon', 'fa-file-alt'), html_escape(r.get('name', ''))))
                if not r.get('is_builtin', False):
                    html.append(' <span style="cursor:pointer;color:#dc2626;font-size:10px;margin-left:auto" '
                        'onclick="event.stopPropagation();RB.deleteReport(\'{0}\',{1})"><i class="fas fa-trash"></i></span>'.format(
                            html_escape(r['id']), 'true' if r.get('is_shared', False) else 'false'))
                html.append('</div>')
        html.append('</div></div>')

    html.append('</div>')
    html.append('<div class="rb-sidebar-footer">')
    html.append('<button class="rb-new-report-btn" onclick="RB.openNewReportModal()"><i class="fas fa-plus"></i> New Custom Report</button>')
    if is_admin_user():
        html.append('<button class="rb-settings-btn" onclick="RB.openSettings()"><i class="fas fa-cog"></i> Settings</button>')
    html.append('</div></div>')
    return ''.join(html)

